/**
 * @fileoverview GridTable Feature — Sorting mixin.
 *
 * Lazy-loaded when sorting is needed (always available since columns are
 * sortable by default, but the heavy logic is separated here).
 *
 * @module module/GridTable/features/sorting
 */

import razyui from '../../../index.js';
import Icons from '../../Icons.js';
import { extractSortValue } from '../helpers.js';
import { applySortOrder } from '../state.js';

/**
 * Install the sorting feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installSorting(ctx) {
    ctx._sortingInstalled = true;

    /**
     * Cycle through sort states: asc → desc → none.
     * @param {string} name — column name
     */
    ctx.toggleSort = (name) => {
        if (!ctx.sortState || ctx.sortState.column !== name) {
            ctx.sortState = { column: name, direction: 'asc' };
        } else if (ctx.sortState.direction === 'asc') {
            ctx.sortState.direction = 'desc';
        } else {
            ctx.sortState = null;
        }
        applySortOrder(ctx);
        ctx.applyFilters();
        ctx.updateSortIndicators();
        ctx.saveState();
    };

    /**
     * Update header cell CSS classes to reflect current sort state.
     */
    ctx.updateSortIndicators = () => {
        if (!ctx.headerColumns) return;
        for (const [name, el] of Object.entries(ctx.headerColumns)) {
            const cell = el[0];
            if (!cell) continue;
            const $cell = razyui(cell);
            $cell.removeClass('is-sorted-asc').removeClass('is-sorted-desc');
            const iconEl = $cell.find('.grid-table-sort-icon');
            if (ctx.sortState && ctx.sortState.column === name) {
                $cell.addClass('is-sorted-' + ctx.sortState.direction);
                iconEl.html(Icons.svg(ctx.sortState.direction === 'asc' ? 'sort-asc' : 'sort-desc', { size: 12, strokeWidth: 2 }));
            } else {
                iconEl.html(Icons.svg('sort-both', { size: 12, strokeWidth: 2 }));
            }
        }
    };
}

export default installSorting;
