/** Default config values used by the GridTable constructor. */
export const DEFAULTS = Object.freeze({
    rowHeight: 32,
    minComponentRowHeight: 40,
    minRowHeight: 16,
    overscan: 10,
    minOverscan: 5,
    minColumnWidth: 80,
    minColumnWidthAbs: 40,
    rowNumberWidth: 32,
    checkboxColWidth: 36,
});

/** Default AJAX configuration merged into `config.ajax`. */
export const AJAX_DEFAULTS = Object.freeze({
    url: '',
    method: 'GET',
    pageSize: 25,
    dataKey: null,
    totalKey: null,
    onResponse: null,
    onBeforeRequest: null,
    onError: null,
});

/** Maximum number of page buttons shown in the pagination footer. */
export const MAX_PAGE_BUTTONS = 7;

/** Debounce delay (ms) for AJAX-mode filter input. */
