/**
 * @fileoverview GridTable Feature — Column / row / group reorder mixin.
 *
 * Lazy-loaded when the column model enables `reorderable` columns
 * or `draggableRows`.
 *
 * Installs the drag-ghost activation helpers and the splice-based
 * reorder operations for columns, column-groups and data rows.
 *
 * @module module/GridTable/features/reorder
 */

import {
    activateColumnDrag,
    startRowDrag,
    handleRowDrag,
    finishRowDrag,
    startPanelColumnDrag,
    handlePanelColumnDrag,
    finishPanelColumnDrag,
} from '../events.js';

import {
    getColumnIndexByX,
    getGroupBounds,
    getGroupBlocks,
    getBlockIndexForGroup,
    getGroupBlockIndexByX,
    remapExpandedRows,
    getDisplayIndexForData,
} from '../helpers.js';

/**
 * Install column / row / group reorder onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installReorder(ctx) {
    ctx._reorderInstalled = true;

    /* ── column drag ghost ───────────────────────────────────── */
    ctx.activateColumnDrag = (e) => activateColumnDrag(ctx, e);

    /* ── row drag ────────────────────────────────────────────── */
    ctx.startRowDrag   = (dataIndex, e) => startRowDrag(ctx, dataIndex, e);
    ctx.handleRowDrag  = (e)            => handleRowDrag(ctx, e);
    ctx.finishRowDrag  = ()             => finishRowDrag(ctx);

    /* ── panel column drag ───────────────────────────────────── */
    ctx.startPanelColumnDrag  = (name, e) => startPanelColumnDrag(ctx, name, e);
    ctx.handlePanelColumnDrag = (e)       => handlePanelColumnDrag(ctx, e);
    ctx.finishPanelColumnDrag = ()        => finishPanelColumnDrag(ctx);

    /* ── helpers exposed for onMouseMove / cancelAllDrags ─── */
    ctx.getColumnIndexByX     = (x) => getColumnIndexByX(x, ctx.columnOrder, ctx.gridColumn);
    ctx.getGroupBounds        = (name) => getGroupBounds(name, ctx.columnOrder, ctx.columnGroups, ctx.pinnedLeft, ctx.pinnedRight);
    ctx.getGroupBlocks        = () => getGroupBlocks(ctx.columnOrder, ctx.columnGroups);
    ctx.getBlockIndexForGroup = (gIdx) => getBlockIndexForGroup(gIdx, ctx.columnOrder, ctx.columnGroups);
    ctx.getGroupBlockIndexByX = (x) => getGroupBlockIndexByX(x, ctx.columnOrder, ctx.columnGroups, ctx.gridColumn);
    ctx.remapExpandedRows     = (oldIdx, newIdx) => remapExpandedRows(ctx.expandedRows, oldIdx, newIdx);
    ctx.getDisplayIndexForData = (dataIndex) => getDisplayIndexForData(ctx.displayList, dataIndex);
}

export default installReorder;
