/**
 * @fileoverview GridTable state — persistence (localStorage save / restore),
 *               client-side filtering & sorting, and display-list management.
 *
 * Every exported function receives the thin `ctx` context object produced
 * by the class's `#ctx()` bridge (see index.js).
 *
 * @module module/GridTable/state
 */

import { extractSortValue, getNestedValue } from './helpers.js';

// ═══════════════════════════════════════════════
// Time-slicing threshold & helpers
// ═══════════════════════════════════════════════

/**
 * Data-size threshold above which filtering / sorting use time-sliced
 * (chunked) processing to avoid blocking the main thread.
 */
export const TIME_SLICE_THRESHOLD = 5000;

/**
 * Number of rows processed per chunk during time-sliced operations.
 */
const CHUNK_SIZE = 2000;

/**
 * Schedule a callback via `requestIdleCallback` (with fallback to `setTimeout`).
 * @param {function} fn
 * @returns {number} handle id
 */
const scheduleIdle = typeof requestIdleCallback === 'function'
    ? (fn) => requestIdleCallback(fn, { timeout: 16 })
    : (fn) => setTimeout(fn, 0);

// ═══════════════════════════════════════════════
// State persistence
// ═══════════════════════════════════════════════

/**
 * Save grid state (widths, order, sort, filters, pins) to localStorage.
 * @param {Object} ctx — grid context
 */
export function saveGridState(ctx) {
    if (!ctx.stateKey) return;
    try {
        const state = {
            columnOrder: [...ctx.columnOrder],
            columnWidths: {},
            sortState: ctx.sortState ? { ...ctx.sortState } : null,
            filterValues: {},
            filterGroupValues: {},
            pinnedLeft: [...ctx.pinnedLeft],
            pinnedRight: [...ctx.pinnedRight],
        };
        // Column widths
        ctx.allColumns.forEach(name => {
            const cc = ctx.gridColumn[name];
            if (cc) state.columnWidths[name] = cc.width;
        });
        // Filter values (text & date-range)
        for (const [col, val] of Object.entries(ctx.filterValues)) {
            if (!val) continue;
            if (ctx.razyui.isPO(val)) {
                state.filterValues[col] = { from: val.from || null, to: val.to || null };
            } else {
                state.filterValues[col] = String(val);
            }
        }
        // Filter group values (Set → array)
        for (const [col, val] of Object.entries(ctx.filterGroupValues)) {
            if (!val) continue;
            state.filterGroupValues[col] = [...val];
        }
        localStorage.setItem(ctx.stateKey, JSON.stringify(state));
    } catch (e) { /* localStorage may be unavailable */ }
}

/**
 * Restore grid state from localStorage.
 * @param {Object} ctx — grid context
 * @returns {boolean} true if state was restored
 */
export function restoreGridState(ctx) {
    if (!ctx.stateKey) return false;
    try {
        const raw = localStorage.getItem(ctx.stateKey);
        if (!raw) return false;
        const state = JSON.parse(raw);
        if (!state || typeof state !== 'object') return false;

        // Column order — only restore columns that still exist
        if (Array.isArray(state.columnOrder)) {
            const allSet = new Set(ctx.allColumns);
            const restored = state.columnOrder.filter(n => allSet.has(n));
            // Append any new columns not in saved state
            ctx.allColumns.forEach(n => { if (!restored.includes(n)) restored.push(n); });
            ctx.columnOrder = restored;
        }

        // Column widths
        if (state.columnWidths && typeof state.columnWidths === 'object') {
            for (const [name, w] of Object.entries(state.columnWidths)) {
                if (ctx.gridColumn[name] && typeof w === 'number' && w > 0) {
                    ctx.gridColumn[name].width = w;
                }
            }
        }

        // Sort state
        if (state.sortState && state.sortState.column && state.sortState.direction) {
            ctx.sortState = { column: state.sortState.column, direction: state.sortState.direction };
        }

        // Pinned columns
        if (Array.isArray(state.pinnedLeft)) {
            ctx.pinnedLeft = state.pinnedLeft.filter(n => ctx.allColumns.includes(n));
        }
        if (Array.isArray(state.pinnedRight)) {
            ctx.pinnedRight = state.pinnedRight.filter(n => ctx.allColumns.includes(n));
        }

        // Filter values
        if (state.filterValues && typeof state.filterValues === 'object') {
            for (const [col, val] of Object.entries(state.filterValues)) {
                if (typeof val === 'string') ctx.filterValues[col] = val;
                else if (ctx.razyui.isPO(val)) ctx.filterValues[col] = { from: val.from || null, to: val.to || null };
            }
        }
        // Filter group values
        if (state.filterGroupValues && typeof state.filterGroupValues === 'object') {
            for (const [col, arr] of Object.entries(state.filterGroupValues)) {
                if (Array.isArray(arr)) ctx.filterGroupValues[col] = new Set(arr);
            }
        }

        return true;
    } catch (e) { return false; }
}

/**
 * Restore filter UI controls to match the restored filter state.
 * @param {Object} ctx — grid context
 */
export function restoreFilterUI(ctx) {
    if (!ctx.showFilterRow) return;
    for (const name of ctx.allColumns) {
        const comp = ctx.filterComponents[name];
        if (!comp) continue;

        // Text filter inputs
        const textVal = ctx.filterValues[name];
        if (textVal && typeof textVal === 'string' && comp.type !== 'date') {
            const cell = ctx.filterCells[name];
            const inp = cell?.find('input[type="text"]')[0];
            if (inp) inp.value = textVal;
        }

        // Date filter
        if (comp.type === 'date' && ctx.filterValues[name]) {
            const val = ctx.filterValues[name];
            if (comp.instance && ctx.razyui.isPO(val)) {
                const rangeStr = [val.from, val.to].filter(Boolean).join(' ~ ');
                const cell = ctx.filterCells[name];
                const inp = cell?.find('input')[0];
                if (inp) inp.value = rangeStr;
            }
        }

        // Combobox group filter
        if ((comp.type === 'group' || comp.type === 'select') && ctx.filterGroupValues[name]) {
            const selected = [...ctx.filterGroupValues[name]];
            if (comp.instance && selected.length) {
                comp.instance.setValue(selected);
            }
        }
    }
}

// ═══════════════════════════════════════════════
// Client-side filtering
// ═══════════════════════════════════════════════

/**
 * Apply all column filters to the data.
 * Sets `ctx.filteredIndices` to the matching indices (or null if no filters).
 * @param {Object} ctx — grid context
 */
export function applyClientFilters(ctx) {
    const hasText = Object.values(ctx.filterValues).some(v => v);
    const hasGroup = Object.values(ctx.filterGroupValues).some(v => v);

    if (!hasText && !hasGroup) {
        ctx.filteredIndices = null;
    } else {
        ctx.filteredIndices = [];
        for (let i = 0; i < ctx.data.length; i++) {
            let match = true;
            // Text / date filters
            for (const [col, filter] of Object.entries(ctx.filterValues)) {
                if (!filter) continue;
                const val = String(getNestedValue(ctx.data[i], col) ?? '');
                if (ctx.razyui.isPO(filter) && ('from' in filter || 'to' in filter)) {
                    // Date range filter { from, to }
                    if (filter.from && val < filter.from) { match = false; break; }
                    if (filter.to && val > filter.to + '\uffff') { match = false; break; }
                } else {
                    // text or select's text input
                    if (!val.toLowerCase().includes(String(filter).toLowerCase())) { match = false; break; }
                }
            }
            // Group (set) filters — select / group types
            if (match) {
                for (const [col, allowedSet] of Object.entries(ctx.filterGroupValues)) {
                    if (!allowedSet) continue;
                    const val = String(getNestedValue(ctx.data[i], col) ?? '');
                    if (!allowedSet.has(val)) { match = false; break; }
                }
            }
            if (match) ctx.filteredIndices.push(i);
        }
    }
}

/**
 * Async time-sliced version of `applyClientFilters`.
 * Processes rows in chunks of `CHUNK_SIZE` with idle-callback yields
 * to avoid blocking the main thread on large datasets.
 *
 * @param {Object} ctx — grid context
 * @returns {Promise<void>}
 */
export function applyClientFiltersAsync(ctx) {
    const hasText = Object.values(ctx.filterValues).some(v => v);
    const hasGroup = Object.values(ctx.filterGroupValues).some(v => v);

    if (!hasText && !hasGroup) {
        ctx.filteredIndices = null;
        return Promise.resolve();
    }

    // Bump generation so stale chunks are discarded on re-trigger
    const gen = (ctx._filterGeneration = (ctx._filterGeneration || 0) + 1);
    const total = ctx.data.length;
    const textEntries = Object.entries(ctx.filterValues).filter(([, v]) => v);
    const groupEntries = Object.entries(ctx.filterGroupValues).filter(([, v]) => v);
    const isPO = ctx.razyui.isPO;
    const result = [];

    return new Promise((resolve) => {
        let offset = 0;

        function processChunk() {
            if (ctx._filterGeneration !== gen) return resolve();  // superseded
            const end = Math.min(offset + CHUNK_SIZE, total);
            for (let i = offset; i < end; i++) {
                let match = true;
                for (const [col, filter] of textEntries) {
                    const val = String(getNestedValue(ctx.data[i], col) ?? '');
                    if (isPO(filter) && ('from' in filter || 'to' in filter)) {
                        if (filter.from && val < filter.from) { match = false; break; }
                        if (filter.to && val > filter.to + '\uffff') { match = false; break; }
                    } else {
                        if (!val.toLowerCase().includes(String(filter).toLowerCase())) { match = false; break; }
                    }
                }
                if (match) {
                    for (const [col, allowedSet] of groupEntries) {
                        const val = String(getNestedValue(ctx.data[i], col) ?? '');
                        if (!allowedSet.has(val)) { match = false; break; }
                    }
                }
                if (match) result.push(i);
            }
            offset = end;
            if (offset < total) {
                scheduleIdle(processChunk);
            } else {
                if (ctx._filterGeneration === gen) ctx.filteredIndices = result;
                resolve();
            }
        }

        scheduleIdle(processChunk);
    });
}

/**
 * Async time-sliced version of `applySortOrder`.
 * Yields before and after the heavy sort so the event loop stays responsive.
 *
 * @param {Object} ctx — grid context
 * @returns {Promise<void>}
 */
export function applySortOrderAsync(ctx) {
    const pool = ctx.filteredIndices || ctx.data.map((_, i) => i);

    if (!ctx.sortState) {
        ctx.sortedIndices = ctx.filteredIndices ? [...ctx.filteredIndices] : null;
        rebuildDisplayList(ctx);
        rebuildOffsets(ctx);
        ctx.updateSpacer();
        return Promise.resolve();
    }

    const gen = (ctx._sortGeneration = (ctx._sortGeneration || 0) + 1);

    return new Promise((resolve) => {
        scheduleIdle(() => {
            if (ctx._sortGeneration !== gen) return resolve();

            const { column, direction } = ctx.sortState;
            const indices = [...pool];
            const isPO = ctx.razyui.isPO;

            indices.sort((a, b) => {
                const va = extractSortValue(getNestedValue(ctx.data[a], column), isPO);
                const vb = extractSortValue(getNestedValue(ctx.data[b], column), isPO);
                if (va === vb) return a - b;
                if (typeof va === 'number' && typeof vb === 'number')
                    return direction === 'asc' ? va - vb : vb - va;
                const sa = String(va).toLowerCase(), sb = String(vb).toLowerCase();
                return sa < sb ? (direction === 'asc' ? -1 : 1)
                     : sa > sb ? (direction === 'asc' ? 1 : -1)
                     : a - b;
            });

            if (ctx._sortGeneration !== gen) return resolve();

            ctx.sortedIndices = indices;
            rebuildDisplayList(ctx);
            rebuildOffsets(ctx);
            ctx.updateSpacer();
            resolve();
        });
    });
}

// ═══════════════════════════════════════════════
// Client-side sorting
// ═══════════════════════════════════════════════

/**
 * Build sorted index array from filtered / full data.
 * Sets `ctx.sortedIndices`, then rebuilds display list + offsets.
 * @param {Object} ctx — grid context
 */
export function applySortOrder(ctx) {
    const pool = ctx.filteredIndices || ctx.data.map((_, i) => i);

    if (!ctx.sortState) {
        ctx.sortedIndices = ctx.filteredIndices ? [...ctx.filteredIndices] : null;
        rebuildDisplayList(ctx);
        rebuildOffsets(ctx);
        ctx.updateSpacer();
        return;
    }

    const { column, direction } = ctx.sortState;
    const indices = [...pool];
    const isPO = ctx.razyui.isPO;

    indices.sort((a, b) => {
        const va = extractSortValue(getNestedValue(ctx.data[a], column), isPO);
        const vb = extractSortValue(getNestedValue(ctx.data[b], column), isPO);
        if (va === vb) return a - b;
        if (typeof va === 'number' && typeof vb === 'number') return direction === 'asc' ? va - vb : vb - va;
        const sa = String(va).toLowerCase(), sb = String(vb).toLowerCase();
        return sa < sb ? (direction === 'asc' ? -1 : 1) : sa > sb ? (direction === 'asc' ? 1 : -1) : a - b;
    });

    ctx.sortedIndices = indices;
    rebuildDisplayList(ctx);
    rebuildOffsets(ctx);
    ctx.updateSpacer();
}

// ═══════════════════════════════════════════════
// Display list
// ═══════════════════════════════════════════════

/**
 * Build flat display list with child rows interleaved after expanded parents.
 * @param {Object} ctx — grid context
 */
export function rebuildDisplayList(ctx) {
    const source = ctx.sortedIndices || ctx.filteredIndices;
    const n = source ? source.length : ctx.data.length;
    const list = [];
    let maxDepth = 0;

    const addChildren = (parentItem, parentDataIndex, parentKey, parentNumber, level) => {
        if (!ctx.subRowFn || !ctx.expandedRows.has(parentKey)) return;
        const children = ctx.subRowFn(parentItem, parentDataIndex);
        if (!Array.isArray(children)) return;
        children.forEach((childItem, ci) => {
            const numbering = parentNumber + '.' + (ci + 1);
            const expansionKey = parentKey + ':' + ci;
            if (level > maxDepth) maxDepth = level;
            list.push({ dataIndex: parentDataIndex, childItem, childIndex: ci, level, numbering, expansionKey });
            addChildren(childItem, parentDataIndex, expansionKey, numbering, level + 1);
        });
    };

    for (let i = 0; i < n; i++) {
        const dataIndex = source ? source[i] : i;
        const numbering = String(i + 1);
        const expansionKey = String(dataIndex);
        list.push({ dataIndex, level: 0, numbering, expansionKey });
        addChildren(ctx.data[dataIndex], dataIndex, expansionKey, numbering, 1);
    }

    ctx.displayList = list;

    // Widen toolside if sub-row depth changed
    if (maxDepth !== ctx.maxSubRowDepth) {
        ctx.maxSubRowDepth = maxDepth;
        ctx.recalcFixedLeft();
    }
}

// ═══════════════════════════════════════════════
// Offset table
// ═══════════════════════════════════════════════

/**
 * Rebuild prefix-sum offsets from display list row heights.
 * @param {Object} ctx — grid context
 */
export function rebuildOffsets(ctx) {
    const heights = ctx.rowHeights;
    const list = ctx.displayList;
    const n = list.length;
    const offsets = [0];
    for (let i = 0; i < n; i++) {
        const entry = list[i];
        const h = entry.childItem
            ? ctx.rowHeight
            : (heights[entry.dataIndex] || ctx.rowHeight);
        offsets.push(offsets[i] + h);
    }
    ctx.rowOffsets = offsets;
}
