/**
 * @fileoverview GridTable barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/GridTable
 */
import { default as razyui } from '../index.js';
import { GridTableDef as DEF } from './GridTable.def.js';
import GridTable from './GridTable/index.js';

// -- Module registration --
// Register the GridTable component to the global razyui object
razyui.GridTable = GridTable;

// -- JIT Component Definition registration --
// If the JIT compiler is available, register the component definition
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// -- Custom Element registration --
/**
 * Registers the GridTable component as a custom HTML element.
 * This allows the component to be used directly in HTML via its defined tag.
 *
 * @returns {Promise<void>} A promise that resolves when the element is registered.
 */
export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, GridTable);
}

export default GridTable;
export const stylesheet = null;
