/**
 * @fileoverview GridTable helpers — pure utility functions for data comparison,
 *               sorting support, column-group calculations, and DOM traversal.
 *
 * Every function is stateless: it receives all data it needs through
 * parameters and returns a result without side-effects.
 *
 * @module module/GridTable/helpers
 */

import razyui from '../../index.js';

// ═══════════════════════════════════════════════
// Nested value resolution (re-exported from core)
// ═══════════════════════════════════════════════

export const getNestedValue = razyui.getNestedValue;

// ═══════════════════════════════════════════════
// Sort value extraction
// ═══════════════════════════════════════════════

/**
 * Extract a comparable primitive from a cell value.
 * Handles plain values, objects ({value, label}), and arrays (ClipBox chips).
 * @param {*} val — raw cell value
 * @param {function} isPO — razyui.isPO reference
 * @returns {string|number}
 */
export function extractSortValue(val, isPO) {
    if (val == null) return '';
    if (typeof val !== 'object') return val;
    if (Array.isArray(val)) return val.map(v => (isPO(v) ? (v.label ?? v.value ?? '') : v)).join(', ');
    return val.label ?? val.value ?? val.text ?? String(val);
}

// ═══════════════════════════════════════════════
// Row-number width
// ═══════════════════════════════════════════════

/**
 * Calculate row-number column width from digit count.
 * @param {number} count — number of data rows
 * @param {boolean} showRowNumbers
 * @returns {number}
 */
export function calcRowNumberWidth(count, showRowNumbers) {
    if (!showRowNumbers || count <= 0) return 32;
    const digits = String(count).length;
    return Math.max(32, digits * 8 + 16);
}

// ═══════════════════════════════════════════════
// DOM traversal
// ═══════════════════════════════════════════════

/**
 * Walk up from target to find the nearest `.grid-table-cell`.
 * @param {HTMLElement} target — event target
 * @param {HTMLElement} headerEl — header container element (stop boundary)
 * @returns {HTMLElement|null}
 */
export function resolveHeaderCell(target, headerEl) {
    const node = razyui(target).closest('.grid-table-cell', headerEl);
    return node.length ? node[0] : null;
}

// ═══════════════════════════════════════════════
// Filter-type detection
// ═══════════════════════════════════════════════

/**
 * Detect the filter type for a column by sampling its data values.
 * - If ≥80% of non-empty values match YYYY-MM-DD → 'date'
 * - If unique value count ≤ 50 and data length > 0 → 'group'
 * - Otherwise → 'text'
 *
 * @param {Array} data
 * @param {string} name — column name
 * @param {number} [sampleSize=200]
 * @returns {string}
 */
export function detectFilterType(data, name, sampleSize = 200) {
    if (!data || data.length === 0) return 'text';
    const dateRe = /^\d{4}-\d{2}-\d{2}/;
    const unique = new Set();
    let dateCount = 0, nonEmpty = 0;
    const limit = Math.min(data.length, sampleSize);

    for (let i = 0; i < limit; i++) {
        const raw = data[i][name];
        const v = raw == null ? '' : String(raw);
        if (v === '') continue;
        nonEmpty++;
        unique.add(v);
        if (dateRe.test(v)) dateCount++;
    }

    if (nonEmpty === 0) return 'text';
    if (dateCount / nonEmpty >= 0.8) return 'date';
    if (unique.size <= 50) return 'group';
    return 'text';
}

/**
 * Collect unique option values from data for a given column.
 * @param {Array} data
 * @param {string} name — column name
 * @returns {Array<{value: string, text: string}>}
 */
export function collectColumnOptions(data, name) {
    const unique = new Map();
    for (const row of data) {
        const raw = row[name];
        const v = String(raw ?? '');
        if (!unique.has(v)) unique.set(v, v || '(empty)');
    }
    return [...unique.entries()]
        .sort((a, b) => a[0].localeCompare(b[0]))
        .map(([value, text]) => ({ value, text }));
}

// ═══════════════════════════════════════════════
// Column-group utilities
// ═══════════════════════════════════════════════

/**
 * Get ordered list of group blocks from current column order.
 * Each block is `{ groupIdx, columns }`.
 *
 * @param {string[]} columnOrder
 * @param {Array} columnGroups
 * @returns {Array<{groupIdx: number, columns: string[]}>}
 */
export function getGroupBlocks(columnOrder, columnGroups) {
    const groupMap = new Map();
    columnGroups.forEach((g, i) => (g.columns || []).forEach(c => groupMap.set(c, i)));
    const blocks = [];
    let prevGIdx;
    for (const name of columnOrder) {
        const gIdx = groupMap.has(name) ? groupMap.get(name) : -1;
        if (gIdx !== prevGIdx || blocks.length === 0) {
            blocks.push({ groupIdx: gIdx, columns: [name] });
            prevGIdx = gIdx;
        } else {
            blocks[blocks.length - 1].columns.push(name);
        }
    }
    return blocks;
}

/**
 * Find which block index contains the given column-group index.
 * @param {number} groupIdx
 * @param {string[]} columnOrder
 * @param {Array} columnGroups
 * @returns {number}
 */
export function getBlockIndexForGroup(groupIdx, columnOrder, columnGroups) {
    const blocks = getGroupBlocks(columnOrder, columnGroups);
    return blocks.findIndex(b => b.groupIdx === groupIdx);
}

/**
 * Find block index from X position in the data-column area.
 * @param {number} x
 * @param {string[]} columnOrder
 * @param {Array} columnGroups
 * @param {Object} gridColumn — { name: { width } }
 * @returns {number}
 */
export function getGroupBlockIndexByX(x, columnOrder, columnGroups, gridColumn) {
    const blocks = getGroupBlocks(columnOrder, columnGroups);
    let pos = 0;
    for (let bi = 0; bi < blocks.length; bi++) {
        let blockW = 0;
        for (const name of blocks[bi].columns) blockW += gridColumn[name]?.width || 0;
        if (x < pos + blockW / 2) return bi;
        pos += blockW;
    }
    return blocks.length - 1;
}

/**
 * Find column index from x position.
 * @param {number} x
 * @param {string[]} columnOrder
 * @param {Object} gridColumn
 * @returns {number}
 */
export function getColumnIndexByX(x, columnOrder, gridColumn) {
    let pos = 0;
    for (let i = 0; i < columnOrder.length; i++) {
        const w = gridColumn[columnOrder[i]]?.width || 0;
        if (x < pos + w / 2) return i;
        pos += w;
    }
    return columnOrder.length - 1;
}

// ═══════════════════════════════════════════════
// Expansion-key remapping
// ═══════════════════════════════════════════════

/**
 * Remap `expandedRows` after a row moves from oldIdx to newIdx in `data`.
 * Expansion keys are string indices (e.g. "5", "5:0:2"), so when rows
 * shift we must rewrite every affected key.
 *
 * @param {Set<string>} expandedRows
 * @param {number} oldIdx
 * @param {number} newIdx
 * @returns {Set<string>} new Set with remapped keys
 */
export function remapExpandedRows(expandedRows, oldIdx, newIdx) {
    if (oldIdx === newIdx || expandedRows.size === 0) return expandedRows;

    const updated = new Set();
    const lo = Math.min(oldIdx, newIdx);
    const hi = Math.max(oldIdx, newIdx);
    const movingDown = newIdx > oldIdx;

    for (const key of expandedRows) {
        const colonPos = key.indexOf(':');
        const topStr = colonPos === -1 ? key : key.substring(0, colonPos);
        const topIdx = parseInt(topStr, 10);
        if (isNaN(topIdx)) { updated.add(key); continue; }
        const suffix = colonPos === -1 ? '' : key.substring(colonPos);

        if (topIdx === oldIdx) {
            updated.add(String(newIdx) + suffix);
        } else if (topIdx >= lo && topIdx <= hi) {
            const shift = movingDown ? -1 : 1;
            updated.add(String(topIdx + shift) + suffix);
        } else {
            updated.add(key);
        }
    }

    return updated;
}

// ═══════════════════════════════════════════════
// Group bounds for reorder constraint
// ═══════════════════════════════════════════════

/**
 * Get the [minIdx, maxIdx] range within `columnOrder` for the column's group.
 * Pinned columns move freely within their pin zone; grouped columns are
 * clamped to their group's contiguous indices; ungrouped columns use the
 * indices not occupied by any group.
 *
 * @param {string} name — column name
 * @param {string[]} columnOrder
 * @param {Array} columnGroups
 * @param {string[]} pinnedLeft
 * @param {string[]} pinnedRight
 * @returns {[number, number]}
 */
export function getGroupBounds(name, columnOrder, columnGroups, pinnedLeft, pinnedRight) {
    // Pinned columns: free to reorder within their pin zone
    if (pinnedLeft.includes(name)) {
        const pinSet = new Set(pinnedLeft);
        let min = columnOrder.length, max = -1;
        columnOrder.forEach((n, i) => {
            if (pinSet.has(n)) { min = Math.min(min, i); max = Math.max(max, i); }
        });
        return min <= max ? [min, max] : [0, columnOrder.length - 1];
    }
    if (pinnedRight.includes(name)) {
        const pinSet = new Set(pinnedRight);
        let min = columnOrder.length, max = -1;
        columnOrder.forEach((n, i) => {
            if (pinSet.has(n)) { min = Math.min(min, i); max = Math.max(max, i); }
        });
        return min <= max ? [min, max] : [0, columnOrder.length - 1];
    }

    if (!columnGroups.length) return [0, columnOrder.length - 1];

    const groupMap = new Map();
    columnGroups.forEach(g => (g.columns || []).forEach(c => groupMap.set(c, g)));
    const myGroup = groupMap.get(name);

    if (myGroup) {
        const siblings = new Set(myGroup.columns || []);
        const pinAll = new Set([...pinnedLeft, ...pinnedRight]);
        let min = columnOrder.length, max = -1;
        columnOrder.forEach((n, i) => {
            if (siblings.has(n) && !pinAll.has(n)) { min = Math.min(min, i); max = Math.max(max, i); }
        });
        return min <= max ? [min, max] : [0, columnOrder.length - 1];
    } else {
        const allGrouped = new Set();
        columnGroups.forEach(g => (g.columns || []).forEach(c => allGrouped.add(c)));
        const pinAll = new Set([...pinnedLeft, ...pinnedRight]);
        let min = columnOrder.length, max = -1;
        columnOrder.forEach((n, i) => {
            if (!allGrouped.has(n) && !pinAll.has(n)) { min = Math.min(min, i); max = Math.max(max, i); }
        });
        return min <= max ? [min, max] : [0, columnOrder.length - 1];
    }
}

// ═══════════════════════════════════════════════
// Display-list lookup
// ═══════════════════════════════════════════════

/**
 * Find the display-list index for a given data-array index.
 * @param {Array} displayList
 * @param {number} dataIndex
 * @returns {number}
 */
export function getDisplayIndexForData(displayList, dataIndex) {
    return displayList.findIndex(e => e.dataIndex === dataIndex && !e.childItem);
}
