/**
 * @fileoverview GridTable events — centralised event binding for scrollbars,
 *               column sort / drag / resize, group drag / resize, row drag,
 *               panel-column drag, viewport scroll, and observer setup.
 *
 * Every exported function receives the thin `ctx` context object produced
 * by the class's `#ctx()` bridge (see index.js).
 *
 * @module module/GridTable/events
 */

import {
    resolveHeaderCell, getGroupBounds, getColumnIndexByX,
    getBlockIndexForGroup, getGroupBlockIndexByX, getGroupBlocks,
    getDisplayIndexForData, remapExpandedRows,
} from './helpers.js';
import { rebuildPanelColumnList, closeContextMenu } from './view.js';
import { updateScrollbarsDirect, updateHScrollbarCached, updatePinZoneTransforms } from './layout.js';
import razyui from '../../index.js';
import Icons from '../Icons.js';
import { rebuildDisplayList, rebuildOffsets } from './state.js';
import { sharedResizeObserver } from '../shared/SharedResizeObserver.js';

// ═══════════════════════════════════════════════
// Observer setup
// ═══════════════════════════════════════════════

/**
 * Create and attach ResizeObserver + MutationObserver for the grid.
 * @param {Object} ctx
 */
export function setupObservers(ctx) {
    // ResizeObserver — shared pool with scope for bulk disconnect
    const guardedCb = (entry) => {
        if (ctx.observerLocked || ctx.resizeState || ctx.groupResizeState) return;
        const el = entry.target;
        if (el === ctx.wrapper[0] || el === ctx.viewport[0]) {
            ctx.observerDirty |= 2;
        } else {
            ctx.observerDirty |= 1;
            ctx.pendingHeaderH = Math.max(ctx.pendingHeaderH, entry.borderBoxSize[0].blockSize);
        }
        ctx.scheduleFlush();
    };
    ctx.resizeCb = guardedCb;
    ctx.resizeScope = sharedResizeObserver.createScope();
    ctx.resizeScope.observe(ctx.wrapper[0], guardedCb);
    ctx.resizeScope.observe(ctx.viewport[0], guardedCb);

    // MutationObserver for cell content changes + container style changes
    ctx.cachedPadYRaw = ctx.container.css('--gt-cell-padding');
    ctx.cellMutObs = new MutationObserver((mutations) => {
        if (ctx.observerLocked || ctx.resizeState || ctx.groupResizeState) return;
        const prevDirty = ctx.observerDirty;
        for (const m of mutations) {
            if (m.type === 'attributes') {
                const padY = ctx.container.css('--gt-cell-padding');
                if (padY !== ctx.cachedPadYRaw) {
                    ctx.cachedPadYRaw = padY;
                    ctx.observerDirty |= 8;
                }
            } else {
                ctx.observerDirty |= 4;
            }
        }
        if (ctx.observerDirty !== prevDirty) ctx.scheduleFlush();
    });
    ctx.cellMutObs.observe(ctx.rows[0], { childList: true, subtree: true });
    ctx.cellMutObs.observe(ctx.container[0], { attributes: true, attributeFilter: ['style'] });
}

// ═══════════════════════════════════════════════
// Delegated filter-row events
// ═══════════════════════════════════════════════

/**
 * Bind delegated input / click events on the filter row container.
 * Covers text-filter input, select-filter text input, and date-filter reset.
 * @param {Object} ctx
 */
export function bindFilterEvents(ctx) {
    if (!ctx.filterRow?.[0]) return;

    // Text & select filter — input event on text inputs
    ctx.filterRow.on('input', (e) => {
        const cell = razyui(e.target).closest('.grid-table-filter-cell');
        if (!cell.length) return;
        const name = cell.attr('data-name');
        if (!name) return;
        ctx.filterValues[name] = e.target.value.trim();
        ctx.applyFilters();
    }, 'input[type="text"]');

    // Date-filter reset button
    ctx.filterRow.on('click', (e) => {
        const cell = razyui(e.target).closest('.grid-table-filter-cell');
        if (!cell.length) return;
        const name = cell.attr('data-name');
        if (!name) return;
        const comp = ctx.filterComponents[name];
        if (comp?.instance) comp.instance.clear();
        ctx.filterValues[name] = '';
        ctx.applyFilters();
    }, '.grid-table-filter-reset');
}

// ═══════════════════════════════════════════════
// Delegated row-element events
// ═══════════════════════════════════════════════

/**
 * Bind delegated events for row checkbox, drag handle, and expand button.
 * Delegated from the rows container so pooled rows need no per-element listeners.
 * @param {Object} ctx
 */
export function bindRowEvents(ctx) {
    if (!ctx.rows?.[0]) return;

    // Checkbox selection
    if (ctx.showCheckbox) {
        ctx.rows.on('change', (e) => {
            const row = razyui(e.target).closest('.grid-table-row');
            if (!row.length) return;
            const idx = parseInt(row.attr('data-index'));
            if (e.target.checked) ctx.selectedRows.add(idx); else ctx.selectedRows.delete(idx);
        }, '.grid-table-checkbox-col input');
    }

    // Drag handle
    if (ctx.showDragHandle) {
        ctx.rows.on('pointerdown', (e) => {
            e.preventDefault();
            const row = razyui(e.target).closest('.grid-table-row');
            if (!row.length) return;
            ctx.startRowDrag(parseInt(row.attr('data-index')), e);
        }, '.is-drag-handle');
    }

    // Expand button
    if (ctx.subRowFn) {
        ctx.rows.on('click', (e) => {
            const row = razyui(e.target).closest('.grid-table-row');
            if (!row.length) return;
            ctx.toggleRowExpansion(row.attr('data-expansion-key'));
        }, '.is-expand');
    }
}

// ═══════════════════════════════════════════════
// Delegated footer-nav events
// ═══════════════════════════════════════════════

/**
 * Bind delegated click on pagination buttons in the footer nav.
 * Buttons carry a `data-page` attribute set by renderFooter.
 * @param {Object} ctx
 */
export function bindFooterEvents(ctx) {
    if (!ctx.footerEl?.[0]) return;

    ctx.footerEl.on('click', (e) => {
        const btn = razyui(e.target).closest('button[data-page]');
        if (!btn.length || btn[0].disabled) return;
        ctx.ajaxPage = parseInt(btn.data('page'));
        ctx.ajaxFetch();
    }, 'button[data-page]');
}

// ═══════════════════════════════════════════════
// Delegated context-menu events
// ═══════════════════════════════════════════════

/**
 * Bind a single delegated click handler on an ephemeral context menu.
 * Menu items and pin-submenu options store their action as `._gtAction`.
 * @param {Object} ctx
 * @param {HTMLElement} menu
 */
export function bindContextMenuActions(ctx, menu) {
    menu.on('click', (e) => {
        const item = razyui(e.target).closest('.grid-table-context-item');
        if (!item.length || !item[0]._gtAction) return;
        closeContextMenu(ctx);
        item[0]._gtAction();
    });
}

// ═══════════════════════════════════════════════
// Core event binding
// ═══════════════════════════════════════════════

/**
 * Bind all interactive events for the grid.
 * @param {Object} ctx
 */
export function bindEvents(ctx) {
    const razyui = ctx.razyui;

    // ── Scrollbar thumb drag ──
    ctx.vscroll.on('pointerdown', (e) => {
        if (e.target === ctx.vthumb[0]) {
            ctx.scrollDrag = { axis: 'y', start: e.clientY, startScroll: ctx.viewport.prop('scrollTop') };
        } else {
            scrollToTrack(ctx, 'y', e.clientY - ctx.vscroll.getRect().top);
        }
        e.preventDefault();
    });
    ctx.hscroll.on('pointerdown', (e) => {
        if (e.target === ctx.hthumb[0]) {
            ctx.scrollDrag = { axis: 'x', start: e.clientX, startScroll: ctx.viewport.prop('scrollLeft') };
        } else {
            scrollToTrack(ctx, 'x', e.clientX - ctx.hscroll.getRect().left);
        }
        e.preventDefault();
    });

    // ── Viewport scroll ──
    const groupHeaderRow = ctx.columnGroups.length
        ? ctx.container.find('.grid-table-header-groups > .grid-table-row')
        : null;

    ctx.viewport.on('scroll', () => {
        razyui.measure(() => {
            const vp = ctx.viewport[0];
            const scrollLeft = vp.scrollLeft || 0;
            const scrollTop = vp.scrollTop;
            const vpH = vp.clientHeight;
            const vpW = vp.clientWidth;
            const scrollWidth = vp.scrollWidth;
            updateHScrollbarCached(ctx);

            razyui.mutate(() => {
                ctx.scrollLeft = scrollLeft;
                ctx.container.toggleClass('is-scrolled', scrollLeft > 0);
                ctx.headerRow.css('transform', `translateX(${-scrollLeft}px)`);
                if (groupHeaderRow) {
                    groupHeaderRow.css('transform', `translateX(${-scrollLeft}px)`);
                }
                if (ctx.filterRow) {
                    ctx.filterRow.css('transform', `translateX(${-scrollLeft}px)`);
                }
                // Pin-zone transforms (replaces position:sticky)
                const maxScroll = Math.max(0, scrollWidth - vpW);
                const rowsEl = ctx.rows[0];
                rowsEl.style.setProperty('--gt-scroll-x', scrollLeft + 'px');
                rowsEl.style.setProperty('--gt-scroll-x-right', (scrollLeft - maxScroll) + 'px');

                updateScrollbarsDirect(ctx, vpH, scrollTop, vpW, scrollLeft);
                ctx.renderDirect(scrollTop, vpH, scrollLeft, vpW);
            });
        });
    });

    // ── Column header: click to sort, drag to reorder ──
    const headerSortDragHandler = (e) => {
        if (e.button !== 0) return;
        if (razyui(e.target).closest('.grid-table-resizer')[0] || razyui(e.target).closest('.grid-table-menu-icon')[0]) return;
        const cell = resolveHeaderCell(e.target, ctx.header[0]);
        if (!cell) return;
        e.preventDefault();
        const name = cell.getAttribute('data-name');
        if (ctx.columnOrder.indexOf(name) < 0) return;
        ctx.dragState = { name, startX: e.clientX, startY: e.clientY, activated: false };
    };
    ctx.headerRow.on('pointerdown', headerSortDragHandler);

    // ── Column resize via resizer handle ──
    const headerResizeHandler = (e) => {
        const cell = resolveHeaderCell(e.target, ctx.header[0]);
        if (!cell) return;
        e.preventDefault();
        const name = cell.getAttribute('data-name');
        const col = ctx.gridColumn[name];
        if (!col) return;
        ctx.resizeState = { name, startX: e.clientX, startWidth: col.width };
    };
    ctx.headerRow.on('pointerdown', headerResizeHandler, '.grid-table-resizer');

    // ── Double-click resizer = auto-fit ──
    const headerDblClickHandler = (e) => {
        const cell = resolveHeaderCell(e.target, ctx.header[0]);
        if (cell) ctx.autoFitColumn(cell.getAttribute('data-name'));
    };
    ctx.headerRow.on('dblclick', headerDblClickHandler, '.grid-table-resizer');

    // ── Bind same handlers to pin-left and pin-right header zones ──
    const headerPinLeft = ctx.container.find('.grid-table-header-columns > .grid-table-pin-left');
    const headerPinRight = ctx.container.find('.grid-table-header-columns > .grid-table-pin-right');
    [headerPinLeft, headerPinRight].forEach(zone => {
        if (!zone[0]) return;
        zone.on('pointerdown', headerSortDragHandler)
            .on('pointerdown', headerResizeHandler, '.grid-table-resizer');
        zone.on('dblclick', headerDblClickHandler, '.grid-table-resizer');
    });

    // ── Column header: menu icon click → context menu ──
    const headerMenuIconHandler = (e) => {
        e.stopPropagation();
        e.preventDefault();
        const cell = resolveHeaderCell(e.target, ctx.header[0]);
        if (!cell) return;
        const name = cell.getAttribute('data-name');
        if (!name) return;
        const rect = razyui(e.target).closest('.grid-table-menu-icon').getRect();
        ctx.showColumnContextMenu(name, rect.left, rect.bottom + 4);
    };
    ctx.headerRow.on('click', headerMenuIconHandler, '.grid-table-menu-icon');
    [headerPinLeft, headerPinRight].forEach(zone => {
        if (zone[0]) zone.on('click', headerMenuIconHandler, '.grid-table-menu-icon');
    });

    // ── Global pointer handlers ──
    const globalOpts = ctx.signal ? { signal: ctx.signal } : undefined;
    razyui(document).on('pointermove', (e) => onMouseMove(ctx, e), globalOpts);
    razyui(document).on('pointerup', (e) => cancelAllDrags(ctx, e), globalOpts);
    razyui(window).on('blur', () => cancelAllDrags(ctx), globalOpts);
    razyui(document).on('visibilitychange', () => { if (document.hidden) cancelAllDrags(ctx); }, globalOpts);

    // ── Group header drag to reorder groups ──
    if (ctx.columnGroups.length) {
        ctx.container.find('.grid-table-header-groups').on('pointerdown', (e) => {
            if (razyui(e.target).is('.grid-table-resizer') || razyui(e.target).is('.grid-table-resizer *')) return;
            const el = razyui(e.target).closest('.grid-table-group-cell', '.grid-table-header-groups');
            if (!el.length) return;
            const gIdx = parseInt(el.attr('data-group-idx'));
            if (isNaN(gIdx) || gIdx < 0) return;
            e.preventDefault();
            ctx.groupDragState = { groupIdx: gIdx, startX: e.clientX, startY: e.clientY, activated: false };
        });

        // ── Group header resize via resizer handle ──
        ctx.container.find('.grid-table-header-groups').on('pointerdown', (e) => {
            if (!razyui(e.target).is('.grid-table-resizer') && !razyui(e.target).is('.grid-table-resizer *')) return;
            const el = razyui(e.target).closest('.grid-table-group-cell', '.grid-table-header-groups');
            if (!el.length) return;
            const gIdx = parseInt(el.attr('data-group-idx'));
            if (isNaN(gIdx) || gIdx < 0) return;
            e.preventDefault();
            const group = ctx.columnGroups[gIdx];
            const pinSet = new Set([...ctx.pinnedLeft, ...ctx.pinnedRight]);
            const cols = (group.columns || []).filter(c => ctx.columnOrder.includes(c) && !pinSet.has(c));
            const startWidths = {};
            let totalW = 0;
            cols.forEach(c => { startWidths[c] = ctx.gridColumn[c]?.width || 0; totalW += startWidths[c]; });
            ctx.groupResizeState = { groupIdx: gIdx, columns: cols, startX: e.clientX, startWidths, startTotalWidth: totalW };
        });
    }
}

// ═══════════════════════════════════════════════
// Unified mouse-move
// ═══════════════════════════════════════════════

/**
 * Unified pointermove handler for all drag operations.
 * @param {Object} ctx
 * @param {PointerEvent} e
 */
export function onMouseMove(ctx, e) {
    const razyui = ctx.razyui;

    if (ctx.scrollDrag) {
        const { axis } = ctx.scrollDrag;
        const delta = axis === 'y' ? e.clientY - ctx.scrollDrag.start : e.clientX - ctx.scrollDrag.start;
        scrollByThumb(ctx, axis, delta, ctx.scrollDrag.startScroll);
        e.preventDefault();
    } else if (ctx.resizeState) {
        if (!ctx.resizeState.active) {
            ctx.resizeState.active = true;
            ctx.container.addClass('is-resizing');
        }
        ctx.resizeState.lastX = e.clientX;
        if (!ctx.resizeRaf) {
            ctx.resizeRaf = requestAnimationFrame(() => {
                ctx.resizeRaf = null;
                if (ctx.resizeState) ctx.applyColumnResize();
            });
        }
    } else if (ctx.dragState) {
        if (!ctx.dragState.activated) {
            const dx = e.clientX - ctx.dragState.startX, dy = e.clientY - ctx.dragState.startY;
            if (Math.abs(dx) < 5 && Math.abs(dy) < 5) return;
            ctx.dragState.activated = true;
            activateColumnDrag(ctx, e);
        }
        const curIdx = ctx.columnOrder.indexOf(ctx.dragState.name);
        const isPinLeft  = ctx.pinnedLeft.includes(ctx.dragState.name);
        const isPinRight = ctx.pinnedRight.includes(ctx.dragState.name);
        let targetIdx;

        if (isPinLeft || isPinRight) {
            // Pinned columns: compute target among same-side pinned columns only
            const pinList = isPinLeft ? ctx.pinnedLeft : ctx.pinnedRight;
            const zoneCls = isPinLeft ? '.grid-table-pin-left' : '.grid-table-pin-right';
            const zone = ctx.container.find('.grid-table-header-columns > ' + zoneCls);
            const zoneRect = zone.getRect();
            const relX = zoneRect ? e.clientX - zoneRect.left : 0;
            // Walk pinned columns in columnOrder to find target
            const pinInOrder = ctx.columnOrder.filter(n => pinList.includes(n));
            let pos = 0;
            targetIdx = ctx.columnOrder.indexOf(pinInOrder[pinInOrder.length - 1]);
            for (let i = 0; i < pinInOrder.length; i++) {
                const w = ctx.gridColumn[pinInOrder[i]]?.width || 0;
                if (relX < pos + w / 2) { targetIdx = ctx.columnOrder.indexOf(pinInOrder[i]); break; }
                pos += w;
            }
        } else {
            // Scrollable columns: use scrollable-space coordinates
            const rect = ctx.header.getRect();
            const relX = e.clientX - rect.left + ctx.scrollLeft - ctx.fixedLeftWidth;
            targetIdx = getColumnIndexByX(relX, ctx.columnOrder, ctx.gridColumn);
            const [groupMin, groupMax] = getGroupBounds(ctx.dragState.name, ctx.columnOrder, ctx.columnGroups, ctx.pinnedLeft, ctx.pinnedRight);
            targetIdx = razyui.clamp(targetIdx, groupMin, groupMax);
        }
        if (targetIdx !== curIdx) ctx.reorderColumn(curIdx, targetIdx);
        if (ctx.dragGhost) ctx.dragGhost.css({ left: e.clientX + 'px', top: e.clientY + 'px' });
    } else if (ctx.rowDragState) {
        handleRowDrag(ctx, e);
    } else if (ctx.groupResizeState) {
        if (!ctx.groupResizeState.active) {
            ctx.groupResizeState.active = true;
            ctx.container.addClass('is-resizing');
        }
        ctx.groupResizeState.lastX = e.clientX;
        if (!ctx.resizeRaf) {
            ctx.resizeRaf = requestAnimationFrame(() => {
                ctx.resizeRaf = null;
                if (ctx.groupResizeState) ctx.applyGroupResize();
            });
        }
    } else if (ctx.panelDragState) {
        handlePanelColumnDrag(ctx, e);
    } else if (ctx.groupDragState) {
        if (!ctx.groupDragState.activated) {
            const dx = e.clientX - ctx.groupDragState.startX, dy = e.clientY - ctx.groupDragState.startY;
            if (Math.abs(dx) < 5 && Math.abs(dy) < 5) return;
            ctx.groupDragState.activated = true;
            ctx.container.addClass('is-column-dragging');
            const group = ctx.columnGroups[ctx.groupDragState.groupIdx];
            const ghost = ctx.colDragGhost;
            ghost.html(Icons.svg('move', { size: 12, strokeWidth: 1.5 }) + ' ' + (group?.label || ''))
                 .css({ 
                left: e.clientX + 'px', top: e.clientY + 'px',
                display: 'block'
            });
            ctx.dragGhost = ghost;
        }
        const rect = ctx.header.getRect();
        const relX = e.clientX - rect.left + ctx.scrollLeft - ctx.fixedLeftWidth;
        // Exclude pinned columns from group block computation
        const pinSet = new Set([...ctx.pinnedLeft, ...ctx.pinnedRight]);
        const scrollableOrder = ctx.columnOrder.filter(n => !pinSet.has(n));
        const curBlockIdx = getBlockIndexForGroup(ctx.groupDragState.groupIdx, scrollableOrder, ctx.columnGroups);
        const targetBlockIdx = getGroupBlockIndexByX(relX, scrollableOrder, ctx.columnGroups, ctx.gridColumn);
        if (targetBlockIdx !== curBlockIdx && targetBlockIdx >= 0) {
            // Map block reorder back to full columnOrder
            const scrollBlocks = getGroupBlocks(scrollableOrder, ctx.columnGroups);
            if (curBlockIdx < 0 || curBlockIdx >= scrollBlocks.length) return;
            const [moved] = scrollBlocks.splice(curBlockIdx, 1);
            scrollBlocks.splice(targetBlockIdx, 0, moved);
            // Rebuild full columnOrder: pinned-left + reordered scrollable + pinned-right
            const pinLeftOrder = ctx.columnOrder.filter(n => ctx.pinnedLeft.includes(n));
            const pinRightOrder = ctx.columnOrder.filter(n => ctx.pinnedRight.includes(n));
            const newScrollable = scrollBlocks.flatMap(b => b.columns);
            ctx.columnOrder.length = 0;
            ctx.columnOrder.push(...pinLeftOrder, ...newScrollable, ...pinRightOrder);
            ctx.reflowColumns();
            ctx.updateVisibleRowLayout();
        }
        if (ctx.dragGhost) ctx.dragGhost.css({ left: e.clientX + 'px', top: e.clientY + 'px' });
    }
}

// ═══════════════════════════════════════════════
// Cancel all drags
// ═══════════════════════════════════════════════

/**
 * Cancel all active drag / resize states.
 * @param {Object} ctx
 * @param {Event} [e]
 */
export function cancelAllDrags(ctx, e) {
    if (ctx.resizeRaf) { cancelAnimationFrame(ctx.resizeRaf); ctx.resizeRaf = null; }
    if (ctx.scrollDrag) ctx.scrollDrag = null;
    if (ctx.resizeState) {
        ctx.applyColumnResize();
        // Lock the manually-resized column — prevent grow/shrink/auto-fit
        const resizedName = ctx.resizeState.name;
        const cc = ctx.columnConfig[resizedName];
        if (cc) {
            cc.grow = 0;
            cc.autoFit = false;
            cc.width = ctx.gridColumn[resizedName].width;
        }
        ctx.container.removeClass('is-resizing');
        // Lightweight reflow — does NOT redistribute grow among other columns
        ctx.reflowAfterResize();
        ctx.scheduleMeasure();
        ctx.resizeState = null;
        ctx.saveState();
    }
    if (ctx.dragState) {
        if (ctx.dragState.activated) {
            const cell = ctx.headerColumns[ctx.dragState.name]?.[0];
            if (cell) razyui(cell).removeClass('is-dragging');
            ctx.container.removeClass('is-column-dragging');
            if (ctx.dragGhost) { ctx.dragGhost.css({ display: 'none' }); ctx.dragGhost = null; }
            ctx.saveState();
        } else if (e) {
            const cc = ctx.columnConfig[ctx.dragState.name];
            if (!cc?.component && !cc?.printHTML) ctx.toggleSort(ctx.dragState.name);
        }
        ctx.dragState = null;
    }
    if (ctx.groupResizeState) {
        ctx.applyGroupResize();
        ctx.container.removeClass('is-resizing');
        ctx.reflowColumns();
        ctx.scheduleMeasure();
        ctx.groupResizeState = null;
        ctx.saveState();
    }
    if (ctx.rowDragState) finishRowDrag(ctx);
    if (ctx.groupDragState) {
        if (ctx.groupDragState.activated) {
            ctx.container.removeClass('is-column-dragging');
            if (ctx.dragGhost) { ctx.dragGhost.css({ display: 'none' }); ctx.dragGhost = null; }
            ctx.reflowColumns();
            ctx.saveState();
        }
        ctx.groupDragState = null;
    }
    if (ctx.panelDragState) finishPanelColumnDrag(ctx);
}

// ═══════════════════════════════════════════════
// Custom scrollbar helpers
// ═══════════════════════════════════════════════

/**
 * Translate thumb drag into viewport scroll.
 * @param {Object} ctx
 * @param {'x'|'y'} axis
 * @param {number} delta
 * @param {number} startScroll
 */
export function scrollByThumb(ctx, axis, delta, startScroll) {
    const vp = ctx.viewport[0];
    if (axis === 'y') {
        const m = parseFloat(getComputedStyle(ctx.vscroll[0]).paddingTop) || 0;
        const tH = (ctx.vscroll.prop('clientHeight') || 0) - m * 2;
        const thumbH = ctx.vthumb.prop('clientHeight') || 0;
        vp.scrollTop = startScroll + delta * ((vp.scrollHeight - vp.clientHeight) / Math.max(1, tH - thumbH));
    } else {
        const m = parseFloat(getComputedStyle(ctx.hscroll[0]).paddingLeft) || 0;
        const tW = (ctx.hscroll.prop('clientWidth') || 0) - m * 2;
        const thumbW = ctx.hthumb.prop('clientWidth') || 0;
        const pinPad = ctx.fixedLeftWidth + ctx.fixedRightWidth;
        const travel = Math.max(1, tW - pinPad - thumbW);
        vp.scrollLeft = startScroll + delta * ((vp.scrollWidth - vp.clientWidth) / travel);
    }
}

/**
 * Jump viewport to a track-click position.
 * @param {Object} ctx
 * @param {'x'|'y'} axis
 * @param {number} pos
 */
export function scrollToTrack(ctx, axis, pos) {
    const vp = ctx.viewport[0];
    if (axis === 'y') {
        const m = parseFloat(getComputedStyle(ctx.vscroll[0]).paddingTop) || 0;
        const tH = (ctx.vscroll.prop('clientHeight') || 0) - m * 2;
        const thumbH = ctx.vthumb.prop('clientHeight') || 0;
        const maxT = Math.max(0, tH - thumbH);
        vp.scrollTop = maxT > 0 ? ((pos - m) / maxT) * (vp.scrollHeight - vp.clientHeight) : 0;
    } else {
        const m = parseFloat(getComputedStyle(ctx.hscroll[0]).paddingLeft) || 0;
        const tW = (ctx.hscroll.prop('clientWidth') || 0) - m * 2;
        const thumbW = ctx.hthumb.prop('clientWidth') || 0;
        const pinPad = ctx.fixedLeftWidth + ctx.fixedRightWidth;
        const travel = Math.max(0, tW - pinPad - thumbW);
        vp.scrollLeft = travel > 0 ? ((pos - m - ctx.fixedLeftWidth) / travel) * (vp.scrollWidth - vp.clientWidth) : 0;
    }
}

// ═══════════════════════════════════════════════
// Column drag ghost
// ═══════════════════════════════════════════════

/**
 * Show column drag ghost.
 * @param {Object} ctx
 * @param {PointerEvent} e
 */
export function activateColumnDrag(ctx, e) {
    const { name } = ctx.dragState;
    const cell = ctx.headerColumns[name]?.[0];
    if (cell) razyui(cell).addClass('is-dragging');
    ctx.container.addClass('is-column-dragging');
    
    const ghost = ctx.colDragGhost;
    ghost.html(Icons.svg('move', { size: 12, strokeWidth: 1.5 }) + ' ' + (ctx.labels[name] || name))
         .css({ 
        left: e.clientX + 'px', top: e.clientY + 'px',
        display: 'block'
    });
    ctx.dragGhost = ghost;
}

// ═══════════════════════════════════════════════
// Panel column drag
// ═══════════════════════════════════════════════

/**
 * Start dragging a column item in the side panel list.
 * @param {Object} ctx
 * @param {string} name
 * @param {PointerEvent} e
 */
export function startPanelColumnDrag(ctx, name, e) {
    const columnList = ctx.sidePanel?.find('.grid-table-column-list');
    if (!columnList?.[0]) return;
    const itemEl = columnList.find(`[data-name="${name}"]`)?.[0];
    if (!itemEl) return;

    ctx.panelDragState = {
        name,
        startY: e.clientY,
        activated: false,
        itemEl,
        columnList: columnList[0],
        indicator: null,
    };
}

/**
 * Handle panel column drag movement.
 * @param {Object} ctx
 * @param {PointerEvent} e
 */
export function handlePanelColumnDrag(ctx, e) {
    const st = ctx.panelDragState;
    if (!st) return;

    if (!st.activated) {
        if (Math.abs(e.clientY - st.startY) < 4) return;
        st.activated = true;
        razyui(st.itemEl).addClass('is-panel-dragging');
        const ind = ctx.sidePanel.find('.grid-table-column-drop-indicator');
        ind.css({ display: 'block' });
        st.indicator = ind;
    }

    const dragPin = st.itemEl.getAttribute('data-pin');
    const dragGroup = st.itemEl.getAttribute('data-group');

    const items = Array.from(st.columnList.querySelectorAll('.grid-table-column-item'));
    const candidates = items.filter(it => {
        const itPin = it.getAttribute('data-pin');
        if (dragPin) return itPin === dragPin;
        const itGroup = it.getAttribute('data-group');
        if (dragGroup) return itGroup === dragGroup && !itPin;
        return !itGroup && !itPin;
    });

    let insertBefore = null;
    for (const cand of candidates) {
        if (cand === st.itemEl) continue;
        const rect = cand.getBoundingClientRect();
        const midY = rect.top + rect.height / 2;
        if (e.clientY < midY) { insertBefore = cand; break; }
    }

    if (st.indicator) {
        const listRect = st.columnList.getBoundingClientRect();
        const scrollTop = st.columnList.scrollTop;
        if (insertBefore) {
            const rect = insertBefore.getBoundingClientRect();
            st.indicator.css('transform', `translateY(${rect.top - listRect.top + scrollTop - 1}px)`);
        } else {
            const last = candidates[candidates.length - 1];
            if (last) {
                const rect = last.getBoundingClientRect();
                st.indicator.css('transform', `translateY(${rect.bottom - listRect.top + scrollTop - 1}px)`);
            }
        }
        st.indicator.css('display', 'block');
    }
    st.insertBefore = insertBefore;
}

/**
 * Finish panel column drag — apply reorder.
 * @param {Object} ctx
 */
export function finishPanelColumnDrag(ctx) {
    const st = ctx.panelDragState;
    if (!st) return;

    if (st.activated) {
        razyui(st.itemEl).removeClass('is-panel-dragging');
        if (st.indicator) st.indicator.css({ display: 'none' });

        const dragName = st.name;
        const insertBefore = st.insertBefore;
        const targetName = insertBefore ? insertBefore.getAttribute('data-name') : null;

        const srcIdx = ctx.columnOrder.indexOf(dragName);
        if (srcIdx >= 0) {
            const order = [...ctx.columnOrder];
            order.splice(srcIdx, 1);

            if (targetName) {
                const tgtIdx = order.indexOf(targetName);
                if (tgtIdx >= 0) order.splice(tgtIdx, 0, dragName);
                else order.push(dragName);
            } else {
                const dragPin = st.itemEl.getAttribute('data-pin');
                if (dragPin) {
                    const pinArr = dragPin === 'left' ? ctx.pinnedLeft : ctx.pinnedRight;
                    const siblings = pinArr.filter(c => order.includes(c));
                    if (siblings.length) {
                        const lastSibIdx = order.indexOf(siblings[siblings.length - 1]);
                        order.splice(lastSibIdx + 1, 0, dragName);
                    } else {
                        order.push(dragName);
                    }
                } else {
                    const dragGroup = st.itemEl.getAttribute('data-group');
                    if (dragGroup) {
                        const group = ctx.columnGroups.find(g => g.label === dragGroup);
                        if (group) {
                            const siblings = (group.columns || []).filter(c => order.includes(c));
                            if (siblings.length) {
                                const lastSibIdx = order.indexOf(siblings[siblings.length - 1]);
                                order.splice(lastSibIdx + 1, 0, dragName);
                            } else { order.push(dragName); }
                        } else { order.push(dragName); }
                    } else { order.push(dragName); }
                }
            }
            ctx.columnOrder = order;
        }

        // Also reorder in group definition / pin array
        const dragPin = st.itemEl.getAttribute('data-pin');
        if (!dragPin) {
            const dragGroup = st.itemEl.getAttribute('data-group');
            if (dragGroup) {
                const group = ctx.columnGroups.find(g => g.label === dragGroup);
                if (group) {
                    const cols = group.columns || [];
                    const oldIdx = cols.indexOf(dragName);
                    if (oldIdx >= 0) {
                        cols.splice(oldIdx, 1);
                        if (targetName) {
                            const newIdx = cols.indexOf(targetName);
                            if (newIdx >= 0) cols.splice(newIdx, 0, dragName);
                            else cols.push(dragName);
                        } else { cols.push(dragName); }
                    }
                }
            } else {
                const allCols = ctx.allColumns;
                const oldIdx = allCols.indexOf(dragName);
                if (oldIdx >= 0) {
                    allCols.splice(oldIdx, 1);
                    if (targetName) {
                        const newIdx = allCols.indexOf(targetName);
                        if (newIdx >= 0) allCols.splice(newIdx, 0, dragName);
                        else allCols.push(dragName);
                    } else { allCols.push(dragName); }
                }
            }
        } else {
            const pinArr = dragPin === 'left' ? ctx.pinnedLeft : ctx.pinnedRight;
            const oldIdx = pinArr.indexOf(dragName);
            if (oldIdx >= 0) {
                pinArr.splice(oldIdx, 1);
                if (targetName) {
                    const newIdx = pinArr.indexOf(targetName);
                    if (newIdx >= 0) pinArr.splice(newIdx, 0, dragName);
                    else pinArr.push(dragName);
                } else { pinArr.push(dragName); }
            }
        }

        // Rebuild the panel list DOM to reflect new order
        rebuildPanelColumnList(ctx);

        // Reflow the grid
        ctx.rowPool.length = 0;
        ctx.poolCells.length = 0;
        ctx.rows.html('');
        ctx.reflowColumns();
        ctx.visibleStart = -1;
        ctx.visibleEnd = -1;
        ctx.scheduleRender(true);
        ctx.saveState();
    }

    ctx.panelDragState = null;
}

// ═══════════════════════════════════════════════
// Row drag-reorder
// ═══════════════════════════════════════════════

/**
 * Start row drag.
 * @param {Object} ctx
 * @param {number} dataIndex
 * @param {PointerEvent} e
 */
export function startRowDrag(ctx, dataIndex, e) {
    const razyui = ctx.razyui;
    const rowEl = ctx.container.find(`.grid-table-row[data-index="${dataIndex}"]`)[0];
    if (rowEl) razyui(rowEl).addClass('is-dragging');

    ctx.rowDragState = {
        dataIndex,
        startY: e.clientY,
        currentIndex: getDisplayIndexForData(ctx.displayList, dataIndex),
        ghost: null,
        rowEl,
    };

    const item = ctx.data[dataIndex] || {};
    const firstCol = ctx.columnOrder[0];
    const label = firstCol ? String(item[firstCol] ?? '') : '';

    const ghost = ctx.rowDragGhost;
    ghost.text(label || 'Row ' + (dataIndex + 1))
         .css({ 
        left: e.clientX + 'px', top: e.clientY + 'px',
        display: 'block'
    });
    ctx.rowDragState.ghost = ghost;
}

/**
 * Handle row drag movement.
 * @param {Object} ctx
 * @param {PointerEvent} e
 */
export function handleRowDrag(ctx, e) {
    if (!ctx.rowDragState) return;
    const ghost = ctx.rowDragState.ghost;
    if (ghost) ghost.css({ left: e.clientX + 'px', top: e.clientY + 'px' });

    const rect = ctx.viewport.getRect();
    const relY = e.clientY - rect.top + ctx.viewport.prop('scrollTop');
    let target = 0;
    for (let i = 0; i < ctx.rowOffsets.length - 1; i++) {
        if (relY > ctx.rowOffsets[i]) target = i;
    }
    ctx.rowDragState.targetIndex = target;
}

/**
 * Finish row drag: reorder data array.
 * @param {Object} ctx
 */
export function finishRowDrag(ctx) {
    if (!ctx.rowDragState) return;
    const { dataIndex, targetIndex, ghost, rowEl } = ctx.rowDragState;
    if (ghost) ghost.css({ display: 'none' });
    if (rowEl) razyui(rowEl).removeClass('is-dragging');

    if (typeof targetIndex === 'number' && targetIndex !== getDisplayIndexForData(ctx.displayList, dataIndex)) {
        const targetDataIdx = ctx.resolveDataIndex(targetIndex);
        const [item] = ctx.data.splice(dataIndex, 1);
        const [height] = ctx.rowHeights.splice(dataIndex, 1);

        // Remap rowState object keys after removing dataIndex
        const savedState = ctx.rowState[dataIndex];
        const newState = {};
        for (const key in ctx.rowState) {
            const k = Number(key);
            if (k === dataIndex) continue;
            if (k > dataIndex) newState[k - 1] = ctx.rowState[k];
            else newState[k] = ctx.rowState[k];
        }

        const insertAt = targetDataIdx > dataIndex ? targetDataIdx : targetDataIdx;
        ctx.data.splice(insertAt, 0, item);
        ctx.rowHeights.splice(insertAt, 0, height);

        // Re-insert the saved state at the new position and shift keys >= insertAt
        const finalState = {};
        for (const key in newState) {
            const k = Number(key);
            if (k >= insertAt) finalState[k + 1] = newState[k];
            else finalState[k] = newState[k];
        }
        if (savedState) finalState[insertAt] = savedState;
        ctx.rowState = finalState;

        ctx.expandedRows = remapExpandedRows(ctx.expandedRows, dataIndex, insertAt);

        rebuildDisplayList(ctx);
        rebuildOffsets(ctx);
        ctx.updateSpacer();
        ctx.visibleStart = -1;
        ctx.visibleEnd = -1;
        ctx.scheduleRender(true);
    }
    ctx.rowDragState = null;
}
