/**
 * @fileoverview GridTable Feature — Column / group resize mixin.
 *
 * Lazy-loaded when resizable columns are present.
 * Provides live-resize during pointer drag and auto-fit on double-click.
 *
 * @module module/GridTable/features/resize
 */

import {
    applyColumnResize,
    applyGroupResize,
    autoSizeColumns,
    autoFitColumn,
} from '../layout.js';

/**
 * Install resize / auto-size feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installResize(ctx) {
    ctx._resizeInstalled = true;

    ctx.applyColumnResize = () => applyColumnResize(ctx);
    ctx.applyGroupResize  = () => applyGroupResize(ctx);
    ctx.autoSizeColumns   = () => autoSizeColumns(ctx);
    ctx.autoFitColumn     = (name) => autoFitColumn(ctx, name);
}

export default installResize;
